flow-diagram.createChart:
{
			parent = reactFlowBorder(reactFlowPadding(reactFlowText('Parent'), all: 5));
			childA = reactFlowBorder(reactFlowPadding(reactFlowText('Child A'), all: 5));
			childB = reactFlowBorder(reactFlowPadding(reactFlowText('Child B'), all: 5));
			reactFlowChart(
				reactFlowPadding(
					reactFlowTree(
						list($parent, $childA, $childB),
						list(
							reactFlowConnection($parent, $childA),
							reactFlowConnection($parent, $childB)
						)
					),
					all: 20
				)
			)
		}
